@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_1a526f09382447129f103c21753531ac.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation
@implements IDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes — Cuisine @CuisineId</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <p>
        Sort:
        <a href="@GetSortUrl("newest")" class="@(CurrentSort == "newest" ? "fw-bold" : "")">Newest</a> |
        <a href="@GetSortUrl("popular")" class="@(CurrentSort == "popular" ? "fw-bold" : "")">Popular</a>
    </p>

    @if (_recipes.Count == 0)
    {
        <p>No recipes found for this cuisine.</p>
    }
    else
    {
        <ul>
            @foreach (var recipe in GetSortedRecipes())
            {
                <li>
                    <strong>@recipe.Title</strong> — @recipe.PrepTimeMinutes min<br />
                    @recipe.Description
                </li>
            }
        </ul>
    }
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private CancellationTokenSource? _loadCts;

    private string CurrentSort => string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
        ? "popular"
        : "newest";

    protected override async Task OnParametersSetAsync()
    {
        // Only reload data when the cuisine changes, not when sort changes.
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight load for the previous cuisine.
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
        }

        _loadCts = new CancellationTokenSource();
        var token = _loadCts.Token;

        _error = null;
        _isRefreshing = _recipes is not null;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, token);

            token.ThrowIfCancellationRequested();

            _recipes = results;
            _loadedCuisineId = CuisineId;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Load was superseded by a newer request — do nothing.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private async Task Retry()
    {
        await LoadRecipesAsync();
    }

    private IEnumerable<Recipe> GetSortedRecipes()
    {
        if (_recipes is null) return Enumerable.Empty<Recipe>();

        return CurrentSort == "popular"
            ? _recipes.OrderBy(r => r.PrepTimeMinutes)
            : _recipes.OrderByDescending(r => r.Id);
    }

    private string GetSortUrl(string sort)
    {
        return Navigation.GetUriWithQueryParameter("sort", sort);
    }

    public void Dispose()
    {
        if (_loadCts is not null)
        {
            _loadCts.Cancel();
            _loadCts.Dispose();
            _loadCts = null;
        }
    }
}

